import React, { useState } from 'react';
import { View, Text, TouchableOpacity, StyleSheet } from 'react-native';

const OfflineTokenGenerator = () => {
  const [currentToken, setCurrentToken] = useState('');

  // Function to generate a random token string
  // It combines a timestamp with two random Math.random() outputs
  // converted to base-36 strings for compactness and uniqueness.
  const generateRandomOfflineToken = () => {
    const timestamp = Date.now().toString(36); // Current timestamp in base-36
    const randomPart1 = Math.random().toString(36).substring(2, 15); // Random part 1
    const randomPart2 = Math.random().toString(36).substring(2, 15); // Random part 2

    // Combine parts to form a unique-ish token string
    return `${timestamp}-${randomPart1}-${randomPart2}`;
  };

  const handleGeneratePress = () => {
    const newToken = generateRandomOfflineToken();
    setCurrentToken(newToken);
    // In an actual offline-first app, this token would typically be
    // stored in a local state management system or AsyncStorage for the session.
    console.log('Generated Offline Session Token:', newToken);
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Offline Session Token Generator</Text>
      <TouchableOpacity style={styles.button} onPress={handleGeneratePress}>
        <Text style={styles.buttonText}>Generate New Token</Text>
      </TouchableOpacity>
      <View style={styles.tokenDisplayContainer}>
        <Text style={styles.labelText}>Current Offline Token:</Text>
        <Text style={styles.tokenText}>{currentToken || 'Press "Generate New Token" to create one.'}</Text>
      </View>
    </View>
  );
};

